// Parse incoming webhook data
const diskData = $input.first().json;
const body = diskData.body || diskData;

// Extract server information
const serverName = body.server_name || 'Unknown Server';
const serverIp = body.server_ip || 'Unknown IP';

const rawOs = (body.os_type || body.os || body.platform || '').toString().toLowerCase();
let osType = 'linux';
if (rawOs.includes('win')) osType = 'windows';
else if (rawOs.includes('darwin') || rawOs.includes('mac')) osType = 'macos';
else if (rawOs.includes('wsl')) osType = 'linux';
else if (rawOs) osType = rawOs;

// Process each disk
let output = [];

if (body.disks && Array.isArray(body.disks)) {
  body.disks.forEach(disk => {
    const usagePercent = Number(disk.usage_percent) || 0;
    const mountpoint = disk.mountpoint || disk.device || 'Unknown';

    // Determine priority based on usage
    let priority = 'Normal';
    if (usagePercent > 90) {
      priority = '1';
    } else if (usagePercent > 80) {
      priority = '2';
    }

    output.push({
      json: {
        server_name: serverName,
        server_ip: serverIp,
        os_type: osType,
        mountpoint: mountpoint,
        device: disk.device || 'N/A',
        total_gb: Number(disk.total_gb) || 0,
        used_gb: Number(disk.used_gb) || 0,
        free_gb: Number(disk.free_gb) || 0,
        usage_percent: usagePercent,
        priority: priority,
        timestamp: disk.timestamp || new Date().toISOString(),
        requires_action: usagePercent > 75
      }
    });
  });
} else {
  // Handle case where no disk data is present
  output.push({
    json: {
      server_name: serverName,
      server_ip: serverIp,
      error: 'No disk data received',
      timestamp: new Date().toISOString(),
      requires_action: false
    }
  });
}

return output;

// Format Jira ticket details for ALL items
const items = $input.all();

const formattedItems = items.map(item => {
  const summary = `${item.json.server_name} (${item.json.server_ip}) - ${item.json.mountpoint} space usage at ${item.json.usage_percent}%`;

  const description = `
**Disk Space Alert**

**Server Details:**
- Server Name: ${item.json.server_name}
- IP Address: ${item.json.server_ip}
- OS Type: ${item.json.os_type}

**Disk Information:**
- Mount Point: ${item.json.mountpoint}
- Device: ${item.json.device}
- Total Space: ${item.json.total_gb} GB
- Used Space: ${item.json.used_gb} GB
- Free Space: ${item.json.free_gb} GB
- Usage Percentage: ${item.json.usage_percent}%

**Alert Details:**
- Priority: ${item.json.priority}
- Timestamp: ${item.json.timestamp}
- Threshold: >75% usage

**Required Action:**
Please investigate disk space usage and take appropriate action to free up space.

This alert was automatically generated by the Azure VM Disk Monitoring System.
`;

  return {
    json: {
      summary: summary,
      description: description,
      priority: item.json.priority,
      server_name: item.json.server_name,
      server_ip: item.json.server_ip,
      mountpoint: item.json.mountpoint,
      usage_percent: item.json.usage_percent,
      labels: ['disk-space', 'azure-vm', 'automated-alert'],
      components: ['infrastructure', 'monitoring'],
      customfield_10000: item.json.timestamp // Custom field for alert timestamp
    }
  };
});

return formattedItems;

// Log successful Jira ticket creation
const item = $input.first().json;

console.log('Jira ticket created successfully:');
console.log('Server:', item.server_name);
console.log('Mount Point:', item.mountpoint);
console.log('Usage:', item.usage_percent + '%');
console.log('Priority:', item.priority);

return $input.all();

// Log normal disk usage (below threshold)
const items = $input.all();

items.forEach(item => {
  if (!item.json.requires_action) {
    console.log('Normal disk usage:');
    console.log('Server:', item.json.server_name);
    console.log('Mount Point:', item.json.mountpoint);
    console.log('Usage:', item.json.usage_percent + '%');
  }
});

return items;
